create or replace function public.record_goods_receipt(p_organization_id uuid,p_purchase_order_id uuid,p_receipt_date date,p_supplier_delivery_reference text,p_notes text,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare po public.purchase_orders%rowtype; v_id uuid; v_no text; line jsonb; item public.purchase_order_items%rowtype; v_qty numeric; v_warehouse uuid; all_received boolean; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','manager']::public.app_role[]) then raise exception 'Insufficient receiving permission'; end if; select * into po from public.purchase_orders where id=p_purchase_order_id and organization_id=p_organization_id for update; if not found or po.status not in ('approved','sent','partially_received') then raise exception 'Purchase order is not receivable'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 then raise exception 'Receipt requires lines'; end if; v_no:=public.next_document_number(p_organization_id,'GRN'); insert into public.goods_receipts(organization_id,branch_id,purchase_order_id,receipt_number,receipt_date,supplier_delivery_reference,status,notes,created_by,posted_at) values(p_organization_id,po.branch_id,po.id,v_no,coalesce(p_receipt_date,current_date),nullif(trim(p_supplier_delivery_reference),''),'posted',nullif(trim(p_notes),''),p_actor_id,now()) returning id into v_id; for line in select value from jsonb_array_elements(p_lines) loop select * into item from public.purchase_order_items where id=(line->>'purchaseOrderItemId')::uuid and purchase_order_id=po.id and organization_id=p_organization_id for update; if not found then raise exception 'Purchase order line not found'; end if; v_qty:=coalesce((line->>'quantity')::numeric,0); v_warehouse:=coalesce(nullif(line->>'warehouseId','')::uuid,item.warehouse_id); if v_qty<=0 or item.received_quantity+v_qty>item.quantity then raise exception 'Received quantity exceeds ordered quantity'; end if; if item.product_id is null or v_warehouse is null then raise exception 'Product and warehouse are required for receipt'; end if; perform public.record_stock_movement(p_organization_id,item.product_id,v_warehouse,'purchase',v_qty,v_no,p_actor_id,'goods_receipt',v_id); insert into public.goods_receipt_items(organization_id,goods_receipt_id,purchase_order_item_id,product_id,warehouse_id,quantity,unit_cost,lot_number,expiry_date) values(p_organization_id,v_id,item.id,item.product_id,v_warehouse,v_qty,item.unit_cost,nullif(trim(line->>'lotNumber'),''),nullif(line->>'expiryDate','')::date); update public.purchase_order_items set received_quantity=received_quantity+v_qty where id=item.id; end loop; select bool_and(received_quantity>=quantity) into all_received from public.purchase_order_items where purchase_order_id=po.id; update public.purchase_orders set status=case when all_received then 'received' else 'partially_received' end,updated_at=now() where id=po.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.goods.received','goods_receipt',v_id,jsonb_build_object('number',v_no,'purchase_order',po.order_number)); return jsonb_build_object('id',v_id,'number',v_no); end $$;

revoke all on function public.record_goods_receipt(uuid,uuid,date,text,text,jsonb,uuid) from public;
grant execute on function public.record_goods_receipt(uuid,uuid,date,text,text,jsonb,uuid) to authenticated;